// src/GeneratorSection.js

import React, { useRef, useState, useEffect, useCallback, memo, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useTheme } from './ThemeContext';
import { useCustomQr } from './useCustomQr';
import ErrorBoundary from './ErrorBoundary';
import Button from './Button';
import ShareAnimatedButton from './ShareAnimatedButton';
import QrCustomizer from './QrCustomizer';
import QrTypes from './QrTypes';
import { useQrHistory } from './useQrHistory';
import QrHistory from './QrHistory';

// ── Static configs outside component ─────────────────────────────────────────
const sectionVariants = {
  hidden:  { opacity: 0, y: 40 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.5, ease: [0.25, 0.46, 0.45, 0.94] } },
};

const cardVariants = {
  hidden:  { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.4, ease: [0.25, 0.46, 0.45, 0.94] } },
};

const tabContentAnim = {
  initial:    { opacity: 0, x: -8 },
  animate:    { opacity: 1, x: 0  },
  exit:       { opacity: 0, x: 8  },
  transition: { duration: 0.15    },
};

const qrAppearAnim = {
  initial:    { opacity: 0, scale: 0.95 },
  animate:    { opacity: 1, scale: 1    },
  transition: { duration: 0.3, ease: 'easeOut' },
};

const tips = [
  'Start URLs with https:// for best results',
  'Shorter content produces cleaner QR codes',
  'Use H error correction when adding a logo',
];

const PARTICLES = [
  { width: 8,  height: 8,  top: '10%', left: '5%',  duration: 4,   delay: 0   },
  { width: 10, height: 10, top: '20%', left: '88%', duration: 5,   delay: 0.5 },
  { width: 6,  height: 6,  top: '55%', left: '6%',  duration: 3.5, delay: 1   },
  { width: 8,  height: 8,  top: '85%', left: '15%', duration: 5.5, delay: 2   },
];

// ── QR grid — CSS animation ───────────────────────────────────────────────────
const QrGridBackground = memo(() => (
  <div
    aria-hidden="true"
    className="pointer-events-none absolute inset-0 overflow-hidden opacity-[0.03] dark:opacity-[0.05]"
  >
    <div
      className="absolute inset-0 grid grid-cols-8"
      style={{ gridTemplateRows: 'repeat(4, 1fr)' }}
    >
      {Array.from({ length: 32 }).map((_, i) => (
        <div
          key={i}
          className="border border-purple-500"
          style={{
            opacity: 0,
            animation: `qrCellPulse ${3 + (i % 4)}s ease-in-out ${(i * 0.08) % 3}s infinite`,
          }}
        />
      ))}
    </div>
  </div>
));
QrGridBackground.displayName = 'QrGridBackground';

// ── Particles — CSS animation ─────────────────────────────────────────────────
const ParticlesLayer = memo(() => (
  <div aria-hidden="true" className="pointer-events-none absolute inset-0">
    {PARTICLES.map((p, i) => (
      <div
        key={i}
        className="absolute rounded-full bg-purple-400/15 dark:bg-purple-400/10"
        style={{
          width:     p.width,
          height:    p.height,
          top:       p.top,
          left:      p.left,
          animation: `particleFloat ${p.duration}s ease-in-out ${p.delay}s infinite`,
        }}
      />
    ))}
  </div>
));
ParticlesLayer.displayName = 'ParticlesLayer';

// ── Static glow orbs ──────────────────────────────────────────────────────────
const GlowOrbs = memo(() => (
  <div aria-hidden="true" className="pointer-events-none absolute inset-0 overflow-hidden">
    <div className="absolute -top-32 left-1/2 -translate-x-1/2 w-[600px] h-[600px] rounded-full bg-purple-500/8 dark:bg-purple-500/10 blur-[120px]" />
    <div className="absolute bottom-0 right-1/4 w-[400px] h-[400px] rounded-full bg-indigo-500/8 dark:bg-indigo-500/10 blur-[100px]" />
  </div>
));
GlowOrbs.displayName = 'GlowOrbs';

// ── Tip cycler ────────────────────────────────────────────────────────────────
const TipCycler = memo(() => {
  const [index, setIndex] = useState(0);
  useEffect(() => {
    const id = setInterval(() => setIndex((p) => (p + 1) % tips.length), 3000);
    return () => clearInterval(id);
  }, []);
  return (
    <div className="relative h-5 overflow-hidden">
      <AnimatePresence mode="wait">
        <motion.p
          key={index}
          initial={{ y: 12,  opacity: 0 }}
          animate={{ y: 0,   opacity: 1 }}
          exit={{   y: -12,  opacity: 0 }}
          transition={{ duration: 0.25 }}
          className="absolute text-xs text-gray-500 dark:text-gray-400"
        >
          💡 {tips[index]}
        </motion.p>
      </AnimatePresence>
    </div>
  );
});
TipCycler.displayName = 'TipCycler';

// ── Scan line ─────────────────────────────────────────────────────────────────
const ScanLine = memo(({ isLoading }) => (
  <AnimatePresence>
    {isLoading && (
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{   opacity: 0 }}
        className="absolute inset-0 rounded-2xl overflow-hidden pointer-events-none z-10"
      >
        <motion.div
          className="absolute left-0 right-0 h-0.5 bg-gradient-to-r from-transparent via-purple-500 to-transparent"
          animate={{ top: ['0%', '100%', '0%'] }}
          transition={{ duration: 1.8, repeat: Infinity, ease: 'easeInOut' }}
        />
        <div className="absolute inset-0 bg-purple-500/5" />
      </motion.div>
    )}
  </AnimatePresence>
));
ScanLine.displayName = 'ScanLine';

// ── Corner decorations — static ───────────────────────────────────────────────
const QrCorners = memo(() => (
  <div aria-hidden="true" className="absolute inset-3 pointer-events-none">
    <div className="absolute top-0 left-0 w-5 h-5 border-t-2 border-l-2 border-purple-500/50 rounded-tl-lg" />
    <div className="absolute top-0 right-0 w-5 h-5 border-t-2 border-r-2 border-purple-500/50 rounded-tr-lg" />
    <div className="absolute bottom-0 left-0 w-5 h-5 border-b-2 border-l-2 border-purple-500/50 rounded-bl-lg" />
    <div className="absolute bottom-0 right-0 w-5 h-5 border-b-2 border-r-2 border-purple-500/50 rounded-br-lg" />
  </div>
));
QrCorners.displayName = 'QrCorners';

// ── Char bar ──────────────────────────────────────────────────────────────────
const CharBar = memo(({ count, limit }) => {
  const pct      = Math.min((count / limit) * 100, 100);
  const isNear   = count > 1000;
  const isAt     = count >= limit;
  const barColor = isAt ? 'bg-red-500' : isNear ? 'bg-yellow-500' : 'bg-purple-500';
  const txtColor = isAt ? 'text-red-500' : isNear ? 'text-yellow-500' : 'text-gray-400 dark:text-gray-500';
  return (
    <div className="mt-3 space-y-1.5">
      <div className="flex items-center justify-between">
        <p className="text-xs text-gray-400 dark:text-gray-600">
          Supports URLs, text, emails, phone numbers
        </p>
        <p className={'text-xs font-medium tabular-nums ' + txtColor}>
          {count} / {limit}
        </p>
      </div>
      <div className="h-1 bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
        <motion.div
          className={'h-full rounded-full ' + barColor}
          animate={{ width: pct + '%' }}
          transition={{ duration: 0.3, ease: 'easeOut' }}
        />
      </div>
    </div>
  );
});
CharBar.displayName = 'CharBar';

// ── QR Display ────────────────────────────────────────────────────────────────
const CustomQrDisplay = memo(({ qrCanvas, isLoading, qrRef }) => {
  if (isLoading) {
    return (
      <div role="status" aria-label="Generating QR code" className="w-64 h-64 flex flex-col items-center justify-center gap-4">
        <div className="relative w-16 h-16">
          <div className="absolute inset-0 rounded-full border-4 border-purple-500/20 border-t-purple-500 animate-spin" />
        </div>
        <p className="text-sm text-gray-400 dark:text-gray-500">Generating...</p>
      </div>
    );
  }
  if (!qrCanvas) {
    return (
      <div className="w-64 h-64 flex flex-col items-center justify-center gap-3 rounded-2xl border-2 border-dashed border-gray-200 dark:border-purple-500/20 bg-gray-50 dark:bg-[#0f0f1a] px-6 text-center">
        <span className="text-4xl" aria-hidden="true">⬡</span>
        <p className="text-sm text-gray-500 dark:text-gray-400 leading-relaxed">
          Enter content to generate your QR code.
        </p>
      </div>
    );
  }
  return (
    <div className="flex flex-col items-center gap-3">
      <div ref={qrRef} className="p-3 bg-white rounded-2xl shadow-lg ring-1 ring-gray-100 dark:ring-purple-500/10">
        <img src={qrCanvas} alt="Generated QR code" className="block" style={{ imageRendering: 'pixelated' }} />
      </div>
      <p className="text-xs text-gray-400 dark:text-gray-600">Scan with any camera app</p>
    </div>
  );
});
CustomQrDisplay.displayName = 'CustomQrDisplay';

// ── Download & Share — module level ──────────────────────────────────────────
const handleCustomDownload = (qrCanvas) => {
  if (!qrCanvas) return;
  const a    = document.createElement('a');
  a.href     = qrCanvas;
  a.download = 'qronetic-qr-code.png';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
};

const handleCustomShare = async (qrCanvas) => {
  if (!qrCanvas || !navigator.share) {
    alert('Sharing not supported. Try downloading instead.');
    return;
  }
  try {
    const res  = await fetch(qrCanvas);
    const blob = await res.blob();
    const file = new File([blob], 'qronetic-qr-code.png', { type: 'image/png' });
    if (navigator.canShare && navigator.canShare({ files: [file] })) {
      await navigator.share({ files: [file], title: 'QR Code — Qronetic', text: 'Generated with Qronetic', url: 'https://www.qronetic.site' });
    }
  } catch (err) {
    if (err.name !== 'AbortError') alert('Failed to share. Try downloading instead.');
  }
};

// ── Tab bar ───────────────────────────────────────────────────────────────────
const TabBar = memo(({ activeTab, setActiveTab }) => (
  <div className="flex gap-1 bg-gray-100 dark:bg-[#1a1a2e] p-1 rounded-xl border border-gray-200 dark:border-purple-500/10">
    <button type="button" onClick={() => setActiveTab(0)} className="relative flex-1 py-2 text-sm font-semibold rounded-lg transition-colors duration-200 z-10">
      {activeTab === 0 && <motion.div layoutId="tab-indicator" className="absolute inset-0 bg-white dark:bg-[#0f0f1a] rounded-lg shadow-sm" transition={{ type: 'spring', stiffness: 400, damping: 30 }} />}
      <span className={"relative z-10 " + (activeTab === 0 ? "text-purple-600 dark:text-purple-400" : "text-gray-500")}>✏️ Content</span>
    </button>
    <button type="button" onClick={() => setActiveTab(1)} className="relative flex-1 py-2 text-sm font-semibold rounded-lg transition-colors duration-200 z-10">
      {activeTab === 1 && <motion.div layoutId="tab-indicator" className="absolute inset-0 bg-white dark:bg-[#0f0f1a] rounded-lg shadow-sm" transition={{ type: 'spring', stiffness: 400, damping: 30 }} />}
      <span className={"relative z-10 " + (activeTab === 1 ? "text-purple-600 dark:text-purple-400" : "text-gray-500")}>🔢 Type</span>
    </button>
    <button type="button" onClick={() => setActiveTab(2)} className="relative flex-1 py-2 text-sm font-semibold rounded-lg transition-colors duration-200 z-10">
      {activeTab === 2 && <motion.div layoutId="tab-indicator" className="absolute inset-0 bg-white dark:bg-[#0f0f1a] rounded-lg shadow-sm" transition={{ type: 'spring', stiffness: 400, damping: 30 }} />}
      <span className={"relative z-10 " + (activeTab === 2 ? "text-purple-600 dark:text-purple-400" : "text-gray-500")}>🎨 Customize</span>
    </button>
  </div>
));
TabBar.displayName = 'TabBar';

// ── Main component ────────────────────────────────────────────────────────────
const GeneratorSection = ({ historyOnly = false }) => {
  const { isDark }  = useTheme();
  const qrRef       = useRef(null);
  const [activeTab, setActiveTab] = useState(0);
  const [focused,   setFocused]   = useState(false);
  const [qrType,    setQrType]    = useState('text');

  const { inputText, setInputText, customOptions, setCustomOptions, qrCanvas, isLoading } = useCustomQr('https://qronetic.site');

  const {
    history: qrHistory, addToHistory, removeFromHistory,
    incrementScan, clearHistory, totalGenerated,
    totalScans, mostScanned, typeBreakdown,
  } = useQrHistory();

  useEffect(() => {
    if (qrCanvas && inputText && !historyOnly) {
      addToHistory({ text: inputText, canvas: qrCanvas, type: qrType });
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [qrCanvas]);

  const charCount = inputText.length;
  const charLimit = 1200;

  const handleFocus       = useCallback(() => setFocused(true),  []);
  const handleBlur        = useCallback(() => setFocused(false), []);
  const handleClear       = useCallback(() => setInputText(''),  [setInputText]);
  const handleTextChange  = useCallback((e) => setInputText(e.target.value.slice(0, 1200)), [setInputText]);
  const handleDownload    = useCallback(() => handleCustomDownload(qrCanvas), [qrCanvas]);
  const handleShare       = useCallback(() => handleCustomShare(qrCanvas),    [qrCanvas]);

  const handleGenerate = useCallback((qrString, type) => {
    setInputText(qrString);
    setQrType(type || 'text');
    setActiveTab(0);
  }, [setInputText]);

  const inputBoxShadow = useMemo(() => ({
    boxShadow: focused
      ? '0 0 0 2px rgba(108,99,255,0.4), 0 4px 16px rgba(108,99,255,0.1)'
      : '0 1px 3px rgba(0,0,0,0.05)',
  }), [focused]);

  // ── Early return for history-only ─────────────────────────────────────────
  if (historyOnly) {
    return (
      <div className="min-h-screen bg-gray-50 dark:bg-[#0f0f1a] pt-8">
        <QrHistory
          history={qrHistory}
          totalGenerated={totalGenerated}
          totalScans={totalScans}
          mostScanned={mostScanned}
          typeBreakdown={typeBreakdown}
          onRemove={removeFromHistory}
          onClear={clearHistory}
          onIncrementScan={incrementScan}
        />
      </div>
    );
  }

  return (
    <motion.section
      id="generator"
      aria-labelledby="generator-heading"
      className="relative min-h-screen bg-gray-50 dark:bg-[#0f0f1a] transition-colors duration-500 px-6 md:px-16 lg:px-24 py-24 overflow-hidden"
      initial="hidden"
      whileInView="visible"
      viewport={{ once: true, amount: 0.1 }}
      variants={sectionVariants}
    >
      <QrGridBackground />
      <ParticlesLayer />
      <GlowOrbs />

      {/* Section header */}
      <div className="mb-14 relative z-10">
        <motion.p
          className="text-sm font-semibold uppercase tracking-widest text-purple-500 dark:text-purple-400 mb-2"
          initial={{ opacity: 0, x: -16 }}
          whileInView={{ opacity: 1, x: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.4 }}
        >
          Generator
        </motion.p>
        <motion.div
          initial={{ opacity: 0, y: 16 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.4, delay: 0.1 }}
        >
          <h2 id="generator-heading" className="text-4xl md:text-5xl font-bold text-gray-900 dark:text-white tracking-tight">
            Create your QR Code
          </h2>
          <motion.div
            className="mt-1 h-1 w-16 bg-gradient-to-r from-purple-500 to-indigo-500 rounded-full"
            initial={{ scaleX: 0, originX: 0 }}
            whileInView={{ scaleX: 1 }}
            viewport={{ once: true }}
            transition={{ duration: 0.5, delay: 0.2 }}
          />
          <p className="mt-4 text-gray-500 dark:text-gray-400 text-base max-w-xl">
            Enter any text, URL, or message — then customize colors, styles, and add your logo.
          </p>
        </motion.div>
      </div>

      {/* Main grid */}
      <div className="relative z-10 grid grid-cols-1 lg:grid-cols-2 gap-10 lg:gap-16 items-start">

        {/* Left panel */}
        <motion.div variants={cardVariants} className="lg:order-1 order-2 flex flex-col gap-4">

          <TabBar activeTab={activeTab} setActiveTab={setActiveTab} />

          <AnimatePresence mode="wait">

            {activeTab === 0 && (
              <motion.div key="content" {...tabContentAnim} className="flex flex-col gap-4">
                <motion.div
                  animate={inputBoxShadow}
                  transition={{ duration: 0.2 }}
                  className="bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/10 rounded-2xl p-6"
                >
                  <div className="flex items-center justify-between mb-3">
                    <label htmlFor="content-input" className="block text-sm font-semibold text-gray-700 dark:text-gray-200 uppercase tracking-wide">
                      Your Content
                    </label>
                    <AnimatePresence>
                      {inputText.length > 0 && (
                        <motion.button
                          initial={{ opacity: 0, scale: 0.8 }}
                          animate={{ opacity: 1, scale: 1   }}
                          exit={{   opacity: 0, scale: 0.8  }}
                          onClick={handleClear}
                          className="text-xs text-gray-400 hover:text-red-400 transition-colors px-2 py-0.5 rounded-md hover:bg-red-50 dark:hover:bg-red-900/20"
                        >
                          Clear ✕
                        </motion.button>
                      )}
                    </AnimatePresence>
                  </div>
                  <textarea
                    id="content-input"
                    rows="10"
                    value={inputText}
                    onChange={handleTextChange}
                    onFocus={handleFocus}
                    onBlur={handleBlur}
                    placeholder="Enter a URL, text, phone number, email..."
                    className="w-full p-4 border-2 border-gray-200 dark:border-purple-500/20 rounded-xl resize-none focus:ring-0 focus:border-purple-500 dark:bg-[#0f0f1a] dark:text-white placeholder-gray-400 dark:placeholder-gray-600 transition-colors duration-200 text-base font-mono outline-none"
                  />
                  <CharBar count={charCount} limit={charLimit} />
                </motion.div>

                <div className="bg-purple-50 dark:bg-purple-900/10 border border-purple-100 dark:border-purple-500/10 rounded-xl p-4">
                  <p className="text-xs font-semibold text-purple-600 dark:text-purple-400 uppercase tracking-wide mb-2">✦ Tips</p>
                  <TipCycler />
                </div>
              </motion.div>
            )}

            {activeTab === 1 && (
              <motion.div key="types" {...tabContentAnim} className="bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/10 rounded-2xl p-6 max-h-[600px] overflow-y-auto no-scrollbar">
                <QrTypes onGenerate={handleGenerate} />
              </motion.div>
            )}

            {activeTab === 2 && (
              <motion.div key="customize" {...tabContentAnim} className="bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/10 rounded-2xl p-6 max-h-[600px] overflow-y-auto no-scrollbar">
                <QrCustomizer options={customOptions} onChange={setCustomOptions} />
              </motion.div>
            )}

          </AnimatePresence>
        </motion.div>

        {/* Right panel — QR preview */}
        <motion.div
          variants={cardVariants}
          className="lg:order-2 order-1 relative flex flex-col items-center justify-center bg-white dark:bg-[#1a1a2e] border border-gray-100 dark:border-purple-500/10 rounded-2xl p-8 shadow-sm overflow-hidden"
        >
          <QrCorners />
          <ScanLine isLoading={isLoading} />

          <div
            aria-hidden="true"
            className="absolute inset-0 opacity-[0.02] dark:opacity-[0.03]"
            style={{ backgroundImage: 'radial-gradient(circle, #6c63ff 1px, transparent 1px)', backgroundSize: '24px 24px' }}
          />

          <div className="relative z-10 w-full flex flex-col items-center">
            <ErrorBoundary fallback={<p className="text-gray-500 dark:text-gray-400 text-sm">Could not generate QR code.</p>}>
              <motion.div key={qrCanvas} {...qrAppearAnim}>
                <CustomQrDisplay qrCanvas={qrCanvas} isLoading={isLoading} qrRef={qrRef} />
              </motion.div>
            </ErrorBoundary>

            <div className="flex justify-center mt-8 w-full max-w-xs gap-4">
              <Button onClick={handleDownload} ariaLabel="Download QR code">Download</Button>
              <ShareAnimatedButton onClick={handleShare} ariaLabel="Share QR code">Share</ShareAnimatedButton>
            </div>

            <p className="text-xs text-gray-400 dark:text-gray-600 mt-4 text-center">
              PNG format · custom styled
            </p>
          </div>
        </motion.div>

      </div>
    </motion.section> 
  );
};

export default GeneratorSection;