// src/ErrorBoundary.js

import React from 'react';
import { QrCode, RefreshCw, AlertTriangle } from 'lucide-react';

// ── Static reload handler outside class to avoid recreation ──────────────────
const handleReload = () => window.location.reload();

// ── Error fallback UI — extracted so it doesn't re-render with the class ──────
const ErrorFallbackUI = ({ error, errorInfo, onReset }) => (
  <div
    role="alert"
    aria-live="assertive"
    className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-[#0f0f1a] px-6"
  >
    <div className="max-w-md w-full text-center space-y-6">

      {/* Icon cluster */}
      <div className="relative w-24 h-24 mx-auto">
        <div className="absolute inset-0 rounded-full bg-purple-500/10 animate-pulse" />
        <div className="absolute inset-0 flex items-center justify-center">
          <QrCode size={40} className="text-purple-400 opacity-40" />
        </div>
        <div className="absolute -top-1 -right-1 bg-red-500 rounded-full p-1.5">
          <AlertTriangle size={14} className="text-white" />
        </div>
      </div>

      {/* Heading */}
      <div className="space-y-2">
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white tracking-tight">
          Something went wrong
        </h1>
        <p className="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">
          Qronetic ran into an unexpected error. Try refreshing or click below to retry.
        </p>
      </div>

      {/* Error details — dev only */}
      {process.env.NODE_ENV === 'development' && error && (
        <details className="text-left bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-500/20 rounded-xl p-4 text-xs text-red-600 dark:text-red-400 font-mono">
          <summary className="cursor-pointer font-semibold mb-2 text-red-700 dark:text-red-300">
            Error details
          </summary>
          <p className="break-words whitespace-pre-wrap">
            {error.toString()}
          </p>
          {errorInfo && (
            <p className="mt-2 break-words whitespace-pre-wrap opacity-70">
              {errorInfo.componentStack}
            </p>
          )}
        </details>
      )}

      {/* Actions */}
      <div className="flex flex-col sm:flex-row gap-3 justify-center">
        <button
          onClick={onReset}
          className="inline-flex items-center justify-center gap-2 px-6 py-3 rounded-full bg-purple-600 hover:bg-purple-700 text-white font-medium text-sm transition-colors duration-200 hover:shadow-lg hover:shadow-purple-500/25 active:scale-95 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-purple-500 focus-visible:ring-offset-2"
        >
          <RefreshCw size={16} />
          Try Again
        </button>

        <button
          onClick={handleReload}
          className="inline-flex items-center justify-center gap-2 px-6 py-3 rounded-full border border-gray-200 dark:border-purple-500/20 bg-white dark:bg-[#1a1a2e] text-gray-700 dark:text-gray-300 font-medium text-sm transition-colors duration-200 hover:border-purple-500/40 active:scale-95 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-purple-500 focus-visible:ring-offset-2"
        >
          Reload Page
        </button>
      </div>

      {/* Branding */}
      <p className="text-xs text-gray-400 dark:text-gray-600">
        Qronetic &mdash; QR Code Generator &amp; Scanner
      </p>

    </div>
  </div>
);

// ── Error boundary class ──────────────────────────────────────────────────────
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      hasError:  false,
      error:     null,
      errorInfo: null,
    };
    this.handleReset = this.handleReset.bind(this);
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, errorInfo) {
    this.setState({ errorInfo });
    if (process.env.NODE_ENV === 'development') {
      console.error("Qronetic ErrorBoundary:", error, errorInfo);
    }
  }

  handleReset() {
    this.setState({ hasError: false, error: null, errorInfo: null });
  }

  shouldComponentUpdate(nextProps, nextState) {
    return (
      nextState.hasError  !== this.state.hasError  ||
      nextState.error     !== this.state.error     ||
      nextProps.children  !== this.props.children  ||
      nextProps.fallback  !== this.props.fallback
    );
  }

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) return this.props.fallback;

      return (
        <ErrorFallbackUI
          error={this.state.error}
          errorInfo={this.state.errorInfo}
          onReset={this.handleReset}
        />
      );
    }
    return this.props.children;
  }
}

export default ErrorBoundary;