// src/useQrHistory.js

import { useState, useEffect, useCallback, useMemo } from 'react';

const HISTORY_KEY = 'qronetic_history';
const MAX_HISTORY = 10;

// ── Load once at module level — avoids reading localStorage on every render ──
const loadHistory = () => {
  try {
    const stored = localStorage.getItem(HISTORY_KEY);
    return stored ? JSON.parse(stored) : [];
  } catch {
    return [];
  }
};

export const useQrHistory = () => {
  // Lazy initializer — runs once on mount, not on every render
  const [history, setHistory] = useState(loadHistory);

  // ── Persist to localStorage whenever history changes ──────────────────────
  useEffect(() => {
    try {
      localStorage.setItem(HISTORY_KEY, JSON.stringify(history));
    } catch {}
  }, [history]);

  // ── Add entry ─────────────────────────────────────────────────────────────
  const addToHistory = useCallback((entry) => {
    if (!entry.text || !entry.canvas) return;
    setHistory((prev) => {
      if (prev.length > 0 && prev[0].text === entry.text) return prev;
      const newEntry = {
        id:        Date.now(),
        text:      entry.text,
        canvas:    entry.canvas,
        type:      entry.type || 'text',
        scanCount: 0,
        createdAt: new Date().toISOString(),
      };
      return [newEntry, ...prev].slice(0, MAX_HISTORY);
    });
  }, []);

  // ── Remove entry ──────────────────────────────────────────────────────────
  const removeFromHistory = useCallback((id) => {
    setHistory((prev) => prev.filter((e) => e.id !== id));
  }, []);

  // ── Increment scan count ──────────────────────────────────────────────────
  const incrementScan = useCallback((id) => {
    setHistory((prev) =>
      prev.map((e) => e.id === id ? { ...e, scanCount: e.scanCount + 1 } : e)
    );
  }, []);

  // ── Clear all ─────────────────────────────────────────────────────────────
  const clearHistory = useCallback(() => {
    setHistory([]);
    try { localStorage.removeItem(HISTORY_KEY); } catch {}
  }, []);

  // ── Analytics — memoized so they don't recalculate on every render ─────────
  const analytics = useMemo(() => {
    const totalScans = history.reduce((acc, e) => acc + e.scanCount, 0);
    const mostScanned = history.reduce(
      (best, e) => (e.scanCount > (best?.scanCount || 0) ? e : best),
      null
    );
    const typeBreakdown = history.reduce((acc, e) => {
      acc[e.type] = (acc[e.type] || 0) + 1;
      return acc;
    }, {});
    return { totalScans, mostScanned, typeBreakdown };
  }, [history]);

  return {
    history,
    addToHistory,
    removeFromHistory,
    incrementScan,
    clearHistory,
    totalGenerated: history.length,
    totalScans:     analytics.totalScans,
    mostScanned:    analytics.mostScanned,
    typeBreakdown:  analytics.typeBreakdown,
  };
};