// src/utils.js

// ── Compiled once at module load, not on every call ───────────────────────────
const DANGEROUS_PROTOCOLS = /^(javascript|data|vbscript|file|blob):/i;
const HTML_TAGS           = /<[^>]*>?/gm;
const MULTI_WHITESPACE    = /\s+/g;

/**
 * Sanitizes user input before encoding into a QR code.
 * Strips dangerous protocols and HTML tags to prevent XSS.
 */
export function sanitizeForQRCode(input) {
  if (typeof input !== 'string') return '';
  const trimmed = input.trim();
  if (!trimmed) return '';
  if (DANGEROUS_PROTOCOLS.test(trimmed)) return '';
  return trimmed.replace(HTML_TAGS, '').replace(MULTI_WHITESPACE, ' ');
}

/**
 * Checks if a string is a valid http/https URL.
 */
export function isValidUrl(input) {
  try {
    const { protocol } = new URL(input);
    return protocol === 'https:' || protocol === 'http:';
  } catch {
    return false;
  }
}

/**
 * Truncates a string to a max length with an ellipsis.
 */
export function truncate(str, maxLength = 80) {
  if (typeof str !== 'string') return '';
  return str.length > maxLength ? str.slice(0, maxLength) + '...' : str;
}